# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.Entity;

namespace ReviewApp.Controllers
{
    public class ProductController : Controller
    {
        private readonly MyDbContext _db = new MyDbContext();

        // GET: /Product/
        public ActionResult Index(int id)
        {
            var product = _db.Products.Find(id);
            if (product == null)
                return HttpNotFound();

            var reviews = _db.Reviews.Where(r => r.ProductId == id).ToList();
            return View(reviews);
        }

        [HttpPost]
        public ActionResult AddReview(Review review)
        {
            if (ModelState.IsValid)
            {
                _db.Reviews.Add(review);
                _db.SaveChanges();
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            return View("Index");
        }
    }

    public class Review
    {
        public int Id { get; set; }
        [Required]
        public string Text { get; set; }
        public int ProductId { get; set; }
        public virtual Product Product { get; set; }
    }

    public class MyDbContext : DbContext
    {
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}